create extension if not exists "uuid-ossp";
create table if not exists companies(id uuid primary key default uuid_generate_v4(),name text not null,logo_url text,watermark_text text default 'NABNY',subscription_plan text default 'enterprise',created_at timestamptz default now());
create table if not exists employees(id uuid primary key default uuid_generate_v4(),company_id uuid references companies(id) on delete cascade,employee_code text not null,full_name text not null,job_title text,department text,project text,branch text,email text,phone text,iqama_expiry date,contract_expiry date,basic_salary numeric default 0,status text default 'active',created_at timestamptz default now());
create table if not exists attendance_records(id uuid primary key default uuid_generate_v4(),company_id uuid references companies(id) on delete cascade,employee_id uuid references employees(id) on delete cascade,attendance_date date not null,check_in timestamptz,check_out timestamptz,status text default 'present',delay_minutes int default 0,device_status text,location_status text,face_status text,created_at timestamptz default now());
create table if not exists employee_requests(id uuid primary key default uuid_generate_v4(),company_id uuid references companies(id) on delete cascade,employee_id uuid references employees(id) on delete cascade,request_type text not null,status text default 'pending_hr',notes text,created_at timestamptz default now());
create table if not exists generated_forms(id uuid primary key default uuid_generate_v4(),company_id uuid references companies(id) on delete cascade,employee_id uuid references employees(id) on delete set null,title text not null,form_data jsonb default '{}'::jsonb,pdf_url text,created_at timestamptz default now());
create table if not exists audit_logs(id uuid primary key default uuid_generate_v4(),company_id uuid references companies(id) on delete cascade,actor_name text,action text not null,risk_level text default 'low',metadata jsonb default '{}'::jsonb,created_at timestamptz default now());
